const getTier = corks => TIERS.find(t => corks >= t.min && corks <= t.max) || TIERS[0]
const getProgress = corks => {
  const t = getTier(corks)
  if (t.id === 4) return 100
  return Math.min(100, Math.round(((corks - t.min) / (t.max - t.min + 1)) * 100))
}

