// ─── SWIPE CARD ───────────────────────────────────────────────────────────────
function SwipeCard({wine,onSwipe,showPrice}){
  const startX=useRef(null),startY=useRef(null)
  const [drag,setDrag]=useState({x:0,y:0})
  const [gone,setGone]=useState(null)
  const [dragging,setDragging]=useState(false)

  const doSwipe=dir=>{if(gone)return;setGone(dir);setTimeout(()=>onSwipe(dir,wine),320)}
  const onTS=e=>{startX.current=e.touches[0].clientX;startY.current=e.touches[0].clientY;setDragging(true)}
  const onTM=e=>{if(startX.current!=null)setDrag({x:e.touches[0].clientX-startX.current,y:e.touches[0].clientY-startY.current})}
  const onTE=()=>{
    setDragging(false)
    const{x,y}=drag
    if(y<-80&&Math.abs(x)<70)doSwipe('super')
    else if(x>75)doSwipe('right')
    else if(x<-75)doSwipe('left')
    else setDrag({x:0,y:0})
    startX.current=null;startY.current=null
  }
  const lo=Math.min(1,Math.max(0,drag.x/75)),no=Math.min(1,Math.max(0,-drag.x/75)),so=Math.min(1,Math.max(0,-drag.y/75))
  const tf=gone==='left'?'translateX(-130%) rotate(-18deg)':gone==='right'?'translateX(130%) rotate(18deg)':gone==='super'?'translateY(-130%)':
    `translateX(${drag.x}px) translateY(${Math.min(0,drag.y)}px) rotate(${drag.x*0.04}deg)`

  return(
    <div style={{position:'relative',borderRadius:10,overflow:'hidden',width:'100%',aspectRatio:'9/14',
      transform:tf,transition:dragging||gone?'none':'transform 0.3s cubic-bezier(0.25,0.46,0.45,0.94)',opacity:gone?0:1}}
      onTouchStart={onTS} onTouchMove={onTM} onTouchEnd={onTE}>
      {/* Embedded background — instant load */}
      <img src={BG[wine.bg]} alt="" style={{position:'absolute',inset:0,width:'100%',height:'100%',objectFit:'cover',filter:'blur(5px) brightness(0.6)',transform:'scale(1.08)',zIndex:0}}/>
      <div style={{position:'absolute',inset:0,background:'linear-gradient(to bottom,rgba(0,0,0,0.25) 0%,transparent 25%,transparent 50%,rgba(0,0,0,0.88) 100%)',zIndex:1}}/>
      {/* Swipe indicators */}
      <div style={{position:'absolute',top:22,left:18,zIndex:20,opacity:lo,transform:'rotate(-8deg)'}}>
        <div style={{background:'rgba(42,107,69,0.92)',backdropFilter:'blur(12px)',borderRadius:6,padding:'7px 16px',color:H.white,fontSize:13,fontWeight:700,fontFamily:H.body,letterSpacing:'0.08em'}}>MAG ICH</div>
      </div>
      <div style={{position:'absolute',top:22,right:18,zIndex:20,opacity:no,transform:'rotate(8deg)'}}>
        <div style={{background:'rgba(155,27,48,0.92)',backdropFilter:'blur(12px)',borderRadius:6,padding:'7px 16px',color:H.white,fontSize:13,fontWeight:700,fontFamily:H.body,letterSpacing:'0.08em'}}>NEIN</div>
      </div>
      <div style={{position:'absolute',top:'35%',left:'50%',transform:'translate(-50%,-50%)',zIndex:20,opacity:so}}>
        <div style={{background:'rgba(196,150,42,0.96)',backdropFilter:'blur(12px)',borderRadius:6,padding:'8px 20px',color:H.black,fontSize:13,fontWeight:700,fontFamily:H.body,letterSpacing:'0.08em',textAlign:'center',whiteSpace:'nowrap'}}>★ SEHR GERNE</div>
      </div>
      {/* Name top */}
      <div style={{position:'absolute',top:0,left:0,right:0,zIndex:5,padding:'18px 20px 0'}}>
        <div style={{fontFamily:H.display,fontSize:17,color:H.white,fontWeight:700,lineHeight:1.2,letterSpacing:'-0.01em',textShadow:'0 2px 12px rgba(0,0,0,0.6)'}}>{wine.name}</div>
        <div style={{fontSize:11,color:'rgba(255,255,255,0.6)',fontFamily:H.body,marginTop:3}}>{wine.region}</div>
      </div>
      {/* Wine bottle — preloaded URL, over background */}
      <div style={{position:'absolute',inset:0,zIndex:2,display:'flex',alignItems:'center',justifyContent:'center',paddingTop:70,paddingBottom:80}}>
        <img src={wine.img} alt={wine.name} style={{maxHeight:'62%',maxWidth:'50%',objectFit:'contain',filter:'drop-shadow(0 20px 48px rgba(0,0,0,0.75)) drop-shadow(0 4px 16px rgba(0,0,0,0.5))'}} onError={e=>e.target.style.display='none'}/>
      </div>
      {/* Bottom info */}
      <div style={{position:'absolute',bottom:0,left:0,right:0,zIndex:5,padding:'0 18px 16px'}}>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
          <div style={{display:'flex',gap:6}}>
            <span style={{fontSize:10,color:'rgba(255,255,255,0.55)',border:'1px solid rgba(255,255,255,0.18)',borderRadius:20,padding:'2px 9px',fontFamily:H.body}}>{wine.type}</span>
            <span style={{fontSize:10,color:'rgba(255,255,255,0.55)',border:'1px solid rgba(255,255,255,0.18)',borderRadius:20,padding:'2px 9px',fontFamily:H.body}}>{wine.year}</span>
          </div>
          {wine.badge&&<span style={{fontSize:9,fontWeight:700,letterSpacing:'0.1em',background:wine.badgeColor||H.red,color:H.white,borderRadius:3,padding:'3px 8px',fontFamily:H.body}}>{wine.badge}</span>}
        </div>
        {showPrice&&wine.price&&<div style={{fontFamily:H.display,fontSize:18,color:H.white,fontWeight:700,marginTop:6}}>{wine.price}</div>}
      </div>
    </div>
  )
}

