// ─── SCREEN: TASTE DNA ────────────────────────────────────────────────────────
function TasteDNAScreen({onComplete}){
  const[idx,setIdx]=useState(0),[liked,setLiked]=useState([]),[supers,setSupers]=useState([])
  const handle=(dir,wine)=>{
    if(dir==='right')setLiked(p=>[...p,wine])
    if(dir==='super'){setLiked(p=>[...p,wine]);setSupers(p=>[...p,wine])}
    if(idx+1>=DNA_WINES.length){
      const all=[...liked,...(dir!=='left'?[wine]:[])]
      const s=[...supers,...(dir==='super'?[wine]:[])]
      const types=all.map(w=>w.type)
      const r=types.filter(t=>t==='Rotwein').length,w2=types.filter(t=>t==='Weißwein').length,ro=types.filter(t=>t==='Roséwein').length,ch=types.filter(t=>t==='Champagner').length
      const max=Math.max(r,w2,ro,ch)
      let dna=ch===max&&ch>0?'champagner':r===max&&r>0?'rotwein':ro===max&&ro>0?'rose':'weisswein'
      onComplete(dna,all,s)
    }else setIdx(i=>i+1)
  }
  const wine=DNA_WINES[idx]
  return(
    <Screen bg="#111">
      <div style={{position:'absolute',top:0,left:0,right:0,zIndex:20,padding:'52px 22px 0',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        <Logo inv/><div style={{fontSize:11,color:'rgba(255,255,255,0.38)',fontFamily:H.body}}>{idx+1} · {DNA_WINES.length}</div>
      </div>
      <div style={{position:'absolute',top:80,left:22,right:22,zIndex:20,height:1,background:'rgba(255,255,255,0.08)'}}>
        <div style={{height:'100%',width:`${(idx/DNA_WINES.length)*100}%`,background:H.red,transition:'width 0.3s ease'}}/>
      </div>
      <div style={{flex:1,display:'flex',flexDirection:'column',padding:'94px 14px 94px',justifyContent:'center'}}>
        <div style={{fontSize:9,color:'rgba(255,255,255,0.28)',letterSpacing:'0.2em',textTransform:'uppercase',fontFamily:H.body,textAlign:'center',marginBottom:12}}>Taste DNA</div>
        <SwipeCard wine={wine} onSwipe={handle}/>
      </div>
      <div style={{position:'absolute',bottom:0,left:0,right:0,padding:'0 14px 26px',zIndex:20}}>
        <SwipeBtns onLeft={()=>handle('left',wine)} onSuper={()=>handle('super',wine)} onRight={()=>handle('right',wine)}/>
      </div>
      <div style={{position:'absolute',bottom:94,left:0,right:0,textAlign:'center',zIndex:15}}>
        <span style={{fontSize:9,color:'rgba(255,255,255,0.16)',fontFamily:H.body,letterSpacing:'0.1em'}}>← swipe · ↑ sehr gerne · →</span>
      </div>
    </Screen>
  )
}

