function DailyDoseScreen({corks,streak,onAddCorks,onAddStreak,onBack}){
  const qs=useMemo(()=>shuffle([...REGIONEN_Q,...REBSORTEN_Q,...FOOD_Q,...DEGUSTATION_Q]).slice(0,10).map(q=>{const opts=shuffle([q.correct,...q.wrong]);return{...q,opts,ci:opts.indexOf(q.correct)}}),[])
  const[idx,setIdx]=useState(0),[sel,setSel]=useState(null),[score,setScore]=useState(0),[done,setDone]=useState(false)
  const q=qs[idx],answered=sel!==null
  const handle=i=>{if(answered)return;setSel(i);if(i===q.ci){setScore(s=>s+1);onAddCorks(3)}}
  const next=()=>{if(idx+1>=qs.length){setDone(true);onAddCorks(20);onAddStreak()}else{setIdx(i=>i+1);setSel(null)}}
  if(done)return(
    <Screen>
      <TopBar onBack={onBack} right={<Cork count={corks} small/>}/>
      <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'40px 28px',textAlign:'center'}}>
        <WineGlass size={52} color={H.red}/>
        <div style={{fontFamily:H.display,fontSize:24,color:H.black,fontWeight:700,marginTop:20,marginBottom:10}}>Daily Dose abgeschlossen.</div>
        <div style={{fontSize:14,color:H.grayMid,fontFamily:H.body,lineHeight:1.7,marginBottom:24}}>{score} von {qs.length} richtig<br/>Streak: <span style={{color:H.red,fontWeight:600}}>{streak} Tage</span></div>
        <div style={{background:H.cream,border:'1px solid rgba(196,150,42,0.2)',borderRadius:4,padding:'14px 28px',marginBottom:24,display:'flex',alignItems:'center',gap:10,justifyContent:'center'}}>
          <img src={CORK} alt="" style={{width:22,height:13}}/><span style={{fontFamily:H.display,fontSize:22,color:H.gold,fontWeight:700}}>+{score*3+20}</span>
          <span style={{fontSize:11,color:H.grayMid,fontFamily:H.body}}>inkl. Tagesbonus</span>
        </div>
        <PBtn onClick={onBack}>Zurück</PBtn>
      </div>
    </Screen>
  )
  return(
    <Screen>
      <TopBar onBack={onBack} right={<div style={{display:'flex',alignItems:'center',gap:8}}><WineGlass size={16} color={H.red}/><span style={{fontSize:12,color:H.red,fontWeight:600,fontFamily:H.body}}>{streak}</span></div>}/>
      <div style={{padding:'0 22px 8px'}}><Progbar val={(idx/qs.length)*100}/></div>
      <div style={{flex:1,display:'flex',flexDirection:'column',padding:'16px 22px',overflowY:'auto'}}>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
          <div style={{fontSize:9,color:H.red,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body}}>Daily Dose</div>
          <div style={{fontSize:10,color:H.grayLight,fontFamily:H.body}}>{idx+1} / {qs.length}</div>
        </div>
        <div style={{fontFamily:H.display,fontSize:18,color:H.black,fontWeight:600,lineHeight:1.4,marginBottom:22}}>{q.q}</div>
        <div style={{display:'flex',flexDirection:'column',gap:9,flex:1}}>
          {q.opts.map((opt,i)=>{
            const isC=i===q.ci,isSel=sel===i
            let bg=H.white,border=`1.5px solid ${H.grayLine}`,color=H.black
            if(answered){if(isC){bg='#EBF5EE';border=`2px solid ${H.green}`;color=H.green}else if(isSel){bg='#F5EAEC';border=`2px solid ${H.red}`;color=H.red}}
            return<button key={i} onClick={()=>handle(i)} style={{padding:'12px 16px',borderRadius:4,background:bg,border,color,fontSize:12,fontFamily:H.body,textAlign:'left',cursor:answered?'default':'pointer',transition:'all 0.2s'}}>{opt}</button>
          })}
        </div>
        {answered&&<div style={{marginTop:12}}>
          <div style={{padding:'10px 14px',background:sel===q.ci?'#EBF5EE':'#F5EAEC',borderRadius:4,marginBottom:10,fontSize:13,color:sel===q.ci?H.green:H.red,fontFamily:H.body,display:'flex',alignItems:'center',gap:8}}>
            {sel===q.ci?<><span>Richtig.</span><div style={{marginLeft:'auto',display:'flex',alignItems:'center',gap:4}}><img src={CORK} alt="" style={{width:15,height:9}}/><span style={{fontWeight:700}}>+3</span></div></>:`Richtig: ${q.opts[q.ci]}`}
          </div>
          <PBtn onClick={next}>{idx+1>=qs.length?'Abschließen':'Weiter'}</PBtn>
        </div>}
      </div>
    </Screen>
  )
}

// ─── SCREEN: LEARN ────────────────────────────────────────────────────────────
function LearnScreen({corks,onAddCorks,onBack}){
  const[view,setView]=useState('menu')
  const vocab=useMemo(()=>shuffle(VOCAB_RAW),[])
  const[vIdx,setVIdx]=useState(0),[flipped,setFlipped]=useState(false),[answered,setAnswered]=useState(null)

  if(view!=='menu'&&view!=='vocab')return(
    <Screen><TopBar onBack={()=>setView('menu')} right={<Cork count={corks} small/>}/>
      <QuizEngine questions={view==='regionen'?REGIONEN_Q:view==='rebsorten'?REBSORTEN_Q:view==='food'?FOOD_Q:DEGUSTATION_Q}
        title={view==='regionen'?'Regionen der Welt':view==='rebsorten'?'Rebsorten':view==='food'?'Food Pairing':'Degustation'}
        onDone={()=>setView('menu')} onAddCorks={onAddCorks}/>
    </Screen>
  )

  if(view==='vocab'){
    const isDone=vIdx>=vocab.length
    if(isDone)return(
      <Screen><TopBar onBack={()=>{setView('menu');setVIdx(0);setFlipped(false);setAnswered(null)}} right={<Cork count={corks} small/>}/>
        <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'40px 28px',textAlign:'center'}}>
          <div style={{width:1,height:36,background:H.red,margin:'0 auto 22px'}}/>
          <div style={{fontFamily:H.display,fontSize:24,color:H.black,fontWeight:700,marginBottom:8}}>Alle Vokabeln gelernt.</div>
          <div style={{fontSize:14,color:H.grayMid,fontFamily:H.body,marginBottom:24,lineHeight:1.7}}>{vocab.length} Karten · +{vocab.length*2} Korken</div>
          <div style={{background:H.cream,border:'1px solid rgba(196,150,42,0.2)',borderRadius:4,padding:'14px 28px',marginBottom:24,display:'flex',alignItems:'center',gap:10,justifyContent:'center'}}>
            <img src={CORK} alt="" style={{width:22,height:13}}/><span style={{fontFamily:H.display,fontSize:22,color:H.gold,fontWeight:700}}>+{vocab.length*2}</span>
          </div>
          <PBtn onClick={onBack}>Zurück</PBtn>
        </div>
      </Screen>
    )
    const card=vocab[vIdx]
    return(
      <Screen>
        <TopBar onBack={()=>{setView('menu');setVIdx(0);setFlipped(false);setAnswered(null)}} right={<Cork count={corks} small/>}/>
        <div style={{padding:'0 22px 10px'}}><Progbar val={(vIdx/vocab.length)*100}/></div>
        <div style={{flex:1,display:'flex',flexDirection:'column',padding:'10px 20px 18px'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
            <CatTag cat={card.cat}/><span style={{fontSize:10,color:H.grayLight,fontFamily:H.body}}>{vIdx+1} / {vocab.length}</span>
          </div>
          <div onClick={()=>{if(!answered)setFlipped(f=>!f)}} style={{flex:1,maxHeight:300,cursor:answered?'default':'pointer',perspective:1000,position:'relative',marginBottom:14}}>
            <div style={{position:'absolute',inset:0,background:H.white,border:`1px solid ${H.grayLine}`,borderRadius:4,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:26,textAlign:'center',backfaceVisibility:'hidden',transform:flipped?'rotateY(180deg)':'rotateY(0deg)',transition:'transform 0.42s ease',boxShadow:'0 2px 16px rgba(0,0,0,0.06)'}}>
              <div style={{fontFamily:H.display,fontSize:28,color:H.black,fontWeight:700,marginBottom:10}}>{card.word}</div>
              <div style={{fontSize:12,color:H.grayMid,fontFamily:H.body}}>Level {card.level}</div>
              {!flipped&&<div style={{marginTop:16,fontSize:11,color:H.grayLight,fontFamily:H.body,border:`1px dashed ${H.grayLine}`,borderRadius:3,padding:'5px 14px',letterSpacing:'0.05em'}}>Tippen zum Aufdecken</div>}
            </div>
            <div style={{position:'absolute',inset:0,background:H.white,border:`1px solid ${H.grayLine}`,borderLeft:`4px solid ${H.red}`,borderRadius:4,display:'flex',flexDirection:'column',justifyContent:'center',padding:22,backfaceVisibility:'hidden',overflowY:'auto',transform:flipped?'rotateY(0deg)':'rotateY(-180deg)',transition:'transform 0.42s ease',boxShadow:'0 2px 16px rgba(0,0,0,0.06)'}}>
              <div style={{fontSize:9,color:H.red,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body,marginBottom:8}}>Definition</div>
              <div style={{fontSize:13,color:H.black,lineHeight:1.75,marginBottom:14,fontFamily:H.body}}>{card.def}</div>
              <div style={{background:H.cream,borderRadius:3,padding:'10px 12px'}}>
                <div style={{fontSize:9,color:H.grayMid,textTransform:'uppercase',letterSpacing:'0.12em',marginBottom:4,fontFamily:H.body}}>Beispiel</div>
                <div style={{fontSize:12,color:H.grayDark,fontStyle:'italic',lineHeight:1.65,fontFamily:H.body}}>{card.example}</div>
              </div>
            </div>
          </div>
          {flipped&&answered===null&&<div style={{display:'flex',gap:10}}>
            <PBtn onClick={()=>setAnswered('wrong')} variant='ghost' style={{flex:1,borderColor:'rgba(155,27,48,0.25)',color:H.red}}>✗ Nochmal</PBtn>
            <PBtn onClick={()=>{setAnswered('correct');onAddCorks(2)}} style={{flex:1}}>✓ Gewusst · +2</PBtn>
          </div>}
          {answered!==null&&<div>
            <div style={{padding:'10px 14px',background:answered==='correct'?'#EBF5EE':'#F5EAEC',borderRadius:4,marginBottom:10,fontSize:13,color:answered==='correct'?H.green:H.red,fontFamily:H.body,display:'flex',alignItems:'center',gap:8}}>
              {answered==='correct'?<><span>Gewusst.</span><div style={{marginLeft:'auto',display:'flex',alignItems:'center',gap:4}}><img src={CORK} alt="" style={{width:15,height:9}}/><span style={{fontWeight:700}}>+2</span></div></>:'Kommt in der nächsten Runde wieder.'}
            </div>
            <PBtn onClick={()=>{if(vIdx+1>=vocab.length)setVIdx(vocab.length);else{setVIdx(i=>i+1);setFlipped(false);setAnswered(null)}}}>
              {vIdx+1>=vocab.length?'Lektion abschließen':'Nächste Karte'}
            </PBtn>
          </div>}
        </div>
      </Screen>
    )
  }

  return(
    <Screen>
      <TopBar onBack={onBack} right={<Cork count={corks} small/>}/>
      <div style={{flex:1,overflowY:'auto',padding:'18px 18px'}}>
        <div style={{fontSize:9,color:H.red,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body,marginBottom:4}}>Lernen</div>
        <div style={{fontFamily:H.display,fontSize:22,color:H.black,fontWeight:600,marginBottom:20}}>Wähle eine Lektion.</div>
        {[
          {id:'vocab',title:'Wein-Vokabeln',sub:`${VOCAB_RAW.length} Begriffe · shuffled · +2 Korken pro Karte`,count:VOCAB_RAW.length,open:true},
          {id:'regionen',title:'Regionen der Welt',sub:`${REGIONEN_Q.length} Fragen · Bordeaux, Pfalz, Toskana, Mendoza`,count:REGIONEN_Q.length,open:true},
          {id:'rebsorten',title:'Rebsorten',sub:`${REBSORTEN_Q.length} Fragen · Riesling, Malbec, Turbiana, Primitivo`,count:REBSORTEN_Q.length,open:true},
          {id:'food',title:'Food Pairing',sub:`${FOOD_Q.length} Fragen · Welcher Wein zu welchem Gericht?`,count:FOOD_Q.length,open:true},
          {id:'degustation',title:'Degustation',sub:`${DEGUSTATION_Q.length} Fragen · Wie professionell verkosten?`,count:DEGUSTATION_Q.length,open:true},
        ].map((l,i)=>(
          <button key={l.id} onClick={()=>l.open&&setView(l.id)} style={{width:'100%',background:H.white,borderRadius:4,padding:'14px 16px',marginBottom:9,border:`1px solid ${H.grayLine}`,display:'flex',alignItems:'center',gap:14,cursor:'pointer',textAlign:'left'}}>
            <div style={{width:32,height:32,borderRadius:3,background:H.cream,display:'flex',alignItems:'center',justifyContent:'center',fontFamily:H.display,fontSize:11,color:H.red,fontWeight:700,flexShrink:0}}>{['I','II','III','IV','V'][i]}</div>
            <div style={{flex:1}}><div style={{fontFamily:H.display,fontSize:15,color:H.black,fontWeight:600}}>{l.title}</div><div style={{fontSize:11,color:H.grayMid,fontFamily:H.body,marginTop:1}}>{l.sub}</div></div>
            <span style={{fontSize:9,background:H.red,color:H.white,borderRadius:2,padding:'3px 8px',fontFamily:H.body,fontWeight:600,flexShrink:0}}>Starten</span>
          </button>
        ))}
      </div>
    </Screen>
  )
}

// ─── SCREEN: DISCOVER ─────────────────────────────────────────────────────────
