        <div style={{textAlign:'center'}}><div style={{fontSize:9,color:H.gold,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body}}>Neue Weine</div><div style={{fontFamily:H.display,fontSize:13,color:H.white,fontWeight:600}}>Passend zu dir entdecken</div></div>
